 69→#[derive(Clone, Copy, Debug, PartialEq, Eq)]
 70→pub enum FileStatus {
 71→    Added,
 72→    Modified,
 73→    Deleted,
 74→    Untracked,
 75→    Unchanged,
 76→}
 77→
 78→#[derive(Clone, Copy, Debug, PartialEq, Eq)]
 79→pub struct GitFileStatus {
 80→    pub index_status: FileStatus,
 81→    pub worktree_status: FileStatus,
 82→    pub conflict: bool,
 83→}
 84→
 85→impl GitFileStatus {
 86→    pub fn staging_state(&self) -> StagingState {
 87→        match (self.index_status, self.worktree_status) {
 88→            (FileStatus::Unchanged, _) => StagingState::Unstaged,
 89→            (_, FileStatus::Unchanged) => StagingState::Staged,
 90→            _ => StagingState::PartiallyStaged,
 91→        }
 92→    }
 93→}
