 44→impl GitStore {
 45→    pub fn new(_cx: &mut Context<Self>) -> Self {
 46→        Self {
 47→            repositories: HashMap::new(),
 48→            active_repository: None,
 49→            next_repository_id: 0,
 50→            _subscriptions: Vec::new(),
 51→        }
 52→    }
 53→
 54→    /// Add a repository to the store. Returns its ID.
 55→    /// Sets it as active if it's the first repository.
 56→    pub fn add_repository(
 57→        &mut self,
 58→        git_repo: Arc<dyn GitRepository>,
 59→        cx: &mut Context<Self>,
 60→    ) -> RepositoryId {
 61→        let id = RepositoryId(self.next_repository_id);
 62→        self.next_repository_id += 1;
 63→
 64→        let repo_entity = cx.new(|cx| Repository::new(git_repo, cx));
 65→
 66→        // Observe the Repository entity: when it notifies, re-emit
 67→        // StatusesChanged so the panel can react.
 68→        let observe_sub = cx.observe(&repo_entity, {
 69→            let id = id;
 70→            move |this: &mut Self, _repo, cx| {
 71→                cx.emit(GitStoreEvent::StatusesChanged(id));
 72→            }
 73→        });
 74→
 75→        // Subscribe to RepositoryEvent for commit/branch changes.
 76→        let event_sub = cx.subscribe(&repo_entity, {
 77→            let id = id;
 78→            move |this: &mut Self, _repo, event: &RepositoryEvent, cx| {
 79→                match event {
 80→                    RepositoryEvent::StatusChanged => {
 81→                        cx.emit(GitStoreEvent::StatusesChanged(id));
 82→                    }
 83→                    RepositoryEvent::IndexChanged => {
 84→                        cx.emit(GitStoreEvent::StatusesChanged(id));
 85→                    }
 86→                    RepositoryEvent::CommitCompleted { was_amend } => {
 87→                        cx.emit(GitStoreEvent::CommitCompleted {
 88→                            repository_id: id,
 89→                            was_amend: *was_amend,
 90→                        });
 91→                    }
 92→                    RepositoryEvent::BranchChanged => {
 93→                        cx.emit(GitStoreEvent::BranchChanged);
 94→                    }
 95→                }
 96→            }
 97→        });
 98→
 99→        self._subscriptions.push(observe_sub);
100→        self._subscriptions.push(event_sub);
101→        self.repositories.insert(id, repo_entity);
102→
103→        // First repository becomes active
104→        if self.active_repository.is_none() {
105→            self.active_repository = Some(id);
106→            cx.emit(GitStoreEvent::ActiveRepositoryChanged);
107→        }
108→
109→        id
110→    }
111→
112→    /// Remove a repository from the store.
113→    pub fn remove_repository(
114→        &mut self,
115→        id: RepositoryId,
116→        cx: &mut Context<Self>,
117→    ) {
118→        self.repositories.remove(&id);
119→
120→        if self.active_repository == Some(id) {
121→            // Pick another repository or None
122→            self.active_repository = self.repositories.keys().next().copied();
123→            cx.emit(GitStoreEvent::ActiveRepositoryChanged);
124→        }
125→    }
126→
127→    /// Get the active repository entity.
128→    pub fn active_repository(&self) -> Option<&Entity<Repository>> {
129→        self.active_repository
130→            .and_then(|id| self.repositories.get(&id))
131→    }
132→
133→    /// Get the active repository ID.
134→    pub fn active_repository_id(&self) -> Option<RepositoryId> {
135→        self.active_repository
136→    }
