138→    /// Set the active repository by ID.
139→    pub fn set_active_repository(
140→        &mut self,
141→        id: RepositoryId,
142→        cx: &mut Context<Self>,
143→    ) {
144→        if self.repositories.contains_key(&id) && self.active_repository != Some(id) {
145→            self.active_repository = Some(id);
146→            cx.emit(GitStoreEvent::ActiveRepositoryChanged);
147→        }
148→    }
