 88→    let mut sink = HunkCollector {
 89→        hunks: Vec::new(),
 90→        base_text: base,
 91→        current_text: current,
 92→    };
 93→
 94→    imara_diff::diff(imara_diff::Algorithm::Histogram, &input, &mut sink);
 95→    sink.hunks
 96→}
